using System.Reflection;
using System.Runtime.InteropServices;

var runtimeDir = RuntimeEnvironment.GetRuntimeDirectory();
var nugetBase = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.UserProfile), ".nuget", "packages");

var extraDirs = new[] {
    "microsoft.agents.ai.abstractions/1.6.2/lib/net10.0",
    "microsoft.agents.ai/1.6.2/lib/net10.0",
    "microsoft.extensions.ai/9.6.0/lib/net10.0",
    "microsoft.extensions.ai.abstractions/9.6.0/lib/net10.0",
};
var allDlls = Directory.GetFiles(runtimeDir, "*.dll").AsEnumerable();
foreach (var d in extraDirs)
{
    var full = Path.Combine(nugetBase, d);
    if (Directory.Exists(full)) allDlls = allDlls.Concat(Directory.GetFiles(full, "*.dll"));
}
var resolver = new PathAssemblyResolver(allDlls);
using var mlc = new MetadataLoadContext(resolver);
var asm = mlc.LoadFromAssemblyPath(args[0]);

// Filter to types containing "Agent" or "Chat" or "Tool" or "Invoke"
foreach (var t in asm.GetExportedTypes().OrderBy(t => t.FullName))
{
    var name = t.Name;
    if (!name.Contains("Agent") && !name.Contains("Chat") && !name.Contains("Tool") && !name.Contains("Invoke") && !name.Contains("Worker"))
        continue;
    Console.WriteLine($"\n=== {t.FullName} (base: {t.BaseType?.FullName}) ===");
    foreach (var c in t.GetConstructors(BindingFlags.Public | BindingFlags.Instance))
        Console.WriteLine($"  ctor({string.Join(", ", c.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
    foreach (var p in t.GetProperties(BindingFlags.Public | BindingFlags.Instance | BindingFlags.DeclaredOnly))
        Console.WriteLine($"  prop {p.Name} : {p.PropertyType}");
    foreach (var m in t.GetMethods(BindingFlags.Public | BindingFlags.Instance | BindingFlags.Static | BindingFlags.DeclaredOnly))
        if (!m.Name.StartsWith("get_") && !m.Name.StartsWith("set_"))
            Console.WriteLine($"  method {m.Name}({string.Join(", ", m.GetParameters().Select(p => $"{p.ParameterType.Name} {p.Name}"))})");
}
CEOF
