using System.ComponentModel;
using System.Net.Http.Json;
using System.Text.Json;
using System.Text.Json.Serialization;
using Microsoft.Extensions.AI;

namespace ResearchAgent;

/// <summary>
/// Provides web search functionality using a search API.
/// Falls back to a simulated search when no API key is configured.
/// </summary>
public sealed class WebSearchTool
{
    private readonly HttpClient _httpClient = new();
    private readonly string? _apiKey;
    private readonly string? _searchEngineId;

    public WebSearchTool()
    {
        _apiKey = Environment.GetEnvironmentVariable("GOOGLE_API_KEY");
        _searchEngineId = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_ENGINE_ID");
    }

