+/// <summary>
+/// Provides web search functionality using a search API.
+/// Falls back to a simulated search when no API key is configured.
+/// </summary>
+public sealed class WebSearchTool
+{
+    private readonly HttpClient _httpClient = new();
+    private readonly string? _apiKey;
+    private readonly string? _searchEngineId;
+
+    public WebSearchTool()
+    {
+        _apiKey = Environment.GetEnvironmentVariable("GOOGLE_API_KEY");
+        _searchEngineId = Environment.GetEnvironmentVariable("GOOGLE_SEARCH_ENGINE_ID");
+    }
+
+    [Description("Searches the web for information on a given query and returns relevant results. Use this to find current information about any topic.")]
+    public async Task<string> SearchWebAsync(
+        [Description("The search query to look up on the web")] string query,
+        [Description("Maximum number of results to return (1-10)")] int maxResults = 5)
+    {
+        maxResults = Math.Clamp(maxResults, 1, 10);
+
+        if (!string.IsNullOrEmpty(_apiKey) && !string.IsNullOrEmpty(_searchEngineId))
+        {
+            return await SearchWithGoogleAsync(query, maxResults);
+        }
+
+        return SimulateSearch(query, maxResults);
+    }
+
+    private async Task<string> SearchWithGoogleAsync(string query, int maxResults)
+    {
+        var url = $"https://www.googleapis.com/customsearch/v1?key={_apiKey}&cx={_searchEngineId}&q={Uri.EscapeDataString(query)}&num={maxResults}";
+
+        try
+        {
+            var response = await _httpClient.GetFromJsonAsync<JsonElement>(url);
+            var items = response.GetProperty("items");
+            var results = new List<string>();
+
+            foreach (var item in items.EnumerateArray().Take(maxResults))
+            {
+                var title = item.GetProperty("title").GetString();
+                var snippet = item.GetProperty("snippet").GetString();
+                var link = item.GetProperty("link").GetString();
+                results.Add($"Title: {title}\nSnippet: {snippet}\nURL: {link}");
+            }
+
+            return string.Join("\n---\n", results);
+        }
+        catch (Exception ex)
+        {
+            return $"Search failed: {ex.Message}. Falling back to simulated results.\n{SimulateSearch(query, maxResults)}";
+        }
+    }
+
+    private static string SimulateSearch(string query, int maxResults)
+    {
+        // Provide simulated results so the agent loop works without a real API key.
+        var results = new List<string>
+        {
+            $"Title: Overview of {query}\nSnippet: {query} is a broad topic encompassing many areas of study. Recent developments have shown significant progress in multiple dimensions including research, applications, and public policy.\nURL: https://example.com/overview",
+            $"Title: Recent Advances in {query}\nSnippet: Researchers have made breakthrough discoveries related to {query}. Key findings include improved methodologies, novel frameworks, and practical applications that are transforming the field.\nURL: https://example.com/advances",
+            $"Title: {query} - Current Trends and Analysis\nSnippet: Analysis of current trends shows that {query} is experiencing rapid growth. Experts predict continued expansion with emerging sub-fields gaining particular attention.\nURL: https://example.com/trends",
+            $"Title: Practical Applications of {query}\nSnippet: Real-world applications of {query} span industries from healthcare to technology. Case studies demonstrate measurable improvements in efficiency and outcomes.\nURL: https://example.com/applications",
+            $"Title: {query} - Challenges and Future Directions\nSnippet: Despite progress, {query} faces challenges including scalability, ethical considerations, and accessibility. Researchers are actively working on solutions.\nURL: https://example.com/challenges",
+        };
+
+        return "[Simulated results — set GOOGLE_API_KEY and GOOGLE_SEARCH_ENGINE_ID for live search]\n"
+            + string.Join("\n---\n", results.Take(maxResults));
+    }
+}
