+// Build the tools the agent can call.
+var searchTool = new WebSearchTool();
+var notepad = new NotepadTool();
+
+var tools = new AITool[]
+{
+    AIFunctionFactory.Create(searchTool.SearchWebAsync),
+    AIFunctionFactory.Create(notepad.SaveNote),
+    AIFunctionFactory.Create(notepad.GetNotes),
+};
+
+// Create the underlying chat client via MEAI + OpenAI provider.
+IChatClient chatClient = new OpenAI.OpenAIClient(apiKey)
+    .GetChatClient(modelId)
+    .AsIChatClient();
+
+// Configure the agent with tools and guardrails.
+var agentOptions = new ChatClientAgentOptions
+{
+    Name = "ResearchAgent",
+    Description = "An AI agent that researches topics by searching the web and taking notes, then produces a summary.",
+    ChatOptions = new ChatOptions
+    {
+        Temperature = 0f,
+        MaxOutputTokens = 4096,
+        Tools = [.. tools],
+    },
+};
+
+var agent = new ChatClientAgent(chatClient, agentOptions);
+
+// Determine the research topic.
+string topic;
+if (args.Length > 0)
+{
+    topic = string.Join(' ', args);
+}
+else
+{
+    Console.Write("Enter a research topic: ");
+    topic = Console.ReadLine()?.Trim() ?? "artificial intelligence";
+}
+
+Console.WriteLine($"\n🔍 Researching: {topic}\n");
+
+var prompt = $"""
+    You are a research assistant. Your task is to research the following topic thoroughly and produce a well-organized summary.
+
+    Topic: {topic}
+
+    Follow these steps:
+    1. Search the web for information about the topic using multiple relevant queries (at least 2-3 different searches).
+    2. As you find important information, save notes using the note-taking tool. Categorize them as 'key-finding', 'statistic', 'source', or 'insight'.
+    3. After gathering enough information, retrieve all your notes to review them.
+    4. Write a comprehensive summary that includes:
+       - An overview of the topic
+       - Key findings and recent developments
+       - Important statistics or data points (if available)
+       - Current challenges and future directions
+       - Sources referenced
+
+    Begin your research now.
+    """;
+
+// Run the agent with streaming output.
+await foreach (var update in agent.RunStreamingAsync(prompt))
+{
+    foreach (var item in update.Message.Contents)
+    {
+        if (item is TextContent text)
+        {
+            Console.Write(text.Text);
+        }
+        else if (item is FunctionCallContent functionCall)
+        {
+            Console.ForegroundColor = ConsoleColor.DarkCyan;
+            Console.Write($"\n  🔧 Calling {functionCall.Name}...");
+            Console.ResetColor();
+        }
+        else if (item is FunctionResultContent functionResult)
+        {
+            Console.ForegroundColor = ConsoleColor.DarkGray;
+            var preview = functionResult.Result?.ToString() ?? "";
+            if (preview.Length > 120)
+            {
+                preview = string.Concat(preview.AsSpan(0, 120), "…");
+            }
+
+            Console.Write($"\n  ✅ {preview}");
+            Console.ResetColor();
+        }
+    }
+}
+
+Console.WriteLine("\n\n✅ Research complete.");

